41: // A Route is a node that contains definitions of how to handle alerts.
42: type Route struct {
43: 	parent *Route
44: 
45: 	// The configuration parameters for matches of this route.
46: 	RouteOpts RouteOpts
47: 
48: 	// Matchers an alert has to fulfill to match
49: 	// this route.
50: 	Matchers labels.Matchers
51: 
52: 	// If true, an alert matches further routes on the same level.
53: 	Continue bool
54: 
55: 	// Children routes of this route.
56: 	Routes []*Route
57: }
58: 
59: // NewRoute returns a new route.
60: func NewRoute(cr *config.Route, parent *Route) *Route {
61: 	// Create default and overwrite with configured settings.
62: 	opts := DefaultRouteOpts
63: 	if parent != nil {
64: 		opts = parent.RouteOpts
65: 	}
66: 
67: 	if cr.Receiver != "" {
68: 		opts.Receiver = cr.Receiver
69: 	}
70: 
71: 	if cr.GroupBy != nil {
72: 		opts.GroupBy = map[model.LabelName]struct{}{}
73: 		for _, ln := range cr.GroupBy {
74: 			opts.GroupBy[ln] = struct{}{}
75: 		}
76: 		opts.GroupByAll = false
77: 	} else {
78: 		if cr.GroupByAll {
79: 			opts.GroupByAll = cr.GroupByAll
80: 		}
81: 	}
82: 
83: 	if cr.GroupWait != nil {
84: 		opts.GroupWait = time.Duration(*cr.GroupWait)
85: 	}
86: 	if cr.GroupInterval != nil {
87: 		opts.GroupInterval = time.Duration(*cr.GroupInterval)
88: 	}
89: 	if cr.RepeatInterval != nil {
90: 		opts.RepeatInterval = time.Duration(*cr.RepeatInterval)
91: 	}
92: 
93: 	// Build matchers.
94: 	var matchers labels.Matchers
95: 
96: 	// cr.Match will be deprecated. This for loop appends matchers.
97: 	for ln, lv := range cr.Match {
98: 		matcher, err := labels.NewMatcher(labels.MatchEqual, ln, lv)
99: 		if err != nil {
100: 			// This error must not happen because the config already validates the yaml.
101: 			panic(err)
102: 		}
103: 		matchers = append(matchers, matcher)
104: 	}
105: 
106: 	// cr.MatchRE will be deprecated. This for loop appends regex matchers.
107: 	for ln, lv := range cr.MatchRE {
108: 		matcher, err := labels.NewMatcher(labels.MatchRegexp, ln, lv.String())
109: 		if err != nil {
110: 			// This error must not happen because the config already validates the yaml.
111: 			panic(err)
112: 		}
113: 		matchers = append(matchers, matcher)
114: 	}
115: 
116: 	// We append the new-style matchers. This can be simplified once the deprecated matcher syntax is removed.
117: 	matchers = append(matchers, cr.Matchers...)
118: 
119: 	sort.Sort(matchers)
120: 
121: 	opts.MuteTimeIntervals = cr.MuteTimeIntervals
122: 	opts.ActiveTimeIntervals = cr.ActiveTimeIntervals
123: 
124: 	route := &Route{
125: 		parent:    parent,
126: 		RouteOpts: opts,
127: 		Matchers:  matchers,
128: 		Continue:  cr.Continue,
129: 	}
130: 
131: 	route.Routes = NewRoutes(cr.Routes, route)
132: 
133: 	return route
134: }
135: 
136: // NewRoutes returns a slice of routes.
137: func NewRoutes(croutes []*config.Route, parent *Route) []*Route {
138: 	res := []*Route{}
139: 	for _, cr := range croutes {
140: 		res = append(res, NewRoute(cr, parent))
141: 	}
142: 	return res
143: }
