172: // Key returns a key for the route. It does not uniquely identify the route in general.
173: func (r *Route) Key() string {
174: 	b := strings.Builder{}
175: 
176: 	if r.parent != nil {
177: 		b.WriteString(r.parent.Key())
178: 		b.WriteRune('/')
179: 	}
180: 	b.WriteString(r.Matchers.String())
181: 	return b.String()
182: }
183: 
184: // ID returns a unique identifier for the route.
185: func (r *Route) ID() string {
186: 	b := strings.Builder{}
187: 
188: 	if r.parent != nil {
189: 		b.WriteString(r.parent.ID())
190: 		b.WriteRune('/')
191: 	}
192: 
193: 	b.WriteString(r.Matchers.String())
194: 
195: 	if r.parent != nil {
196: 		for i := range r.parent.Routes {
197: 			if r == r.parent.Routes[i] {
198: 				b.WriteRune('/')
199: 				b.WriteString(strconv.Itoa(i))
200: 				break
201: 			}
202: 		}
203: 	}
204: 
205: 	return b.String()
206: }
207: 
208: // Walk traverses the route tree in depth-first order.
209: func (r *Route) Walk(visit func(*Route)) {
210: 	visit(r)
211: 	for i := range r.Routes {
212: 		r.Routes[i].Walk(visit)
213: 	}
214: }
